  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
`;

const slideIn = keyframes`
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
`;

const Container = styled.div`
  display: flex;
  height: calc(100vh - 4rem);
  background: #f8fafc;
`;

const Sidebar = styled.div`
  width: 300px;
  background: white;
  border-right: 1px solid #e2e8f0;
  padding: 1.5rem;
  overflow-y: auto;
`;

const MainContent = styled.div`
  flex: 1;
  display: flex;
  flex-direction: column;
`;

const Header = styled.div`
  padding: 1.5rem;
  border-bottom: 1px solid #e2e8f0;
  background: white;
`;

const Title = styled.h1`
  font-size: 1.5rem;
  font-weight: 600;
  color: #1e293b;
  margin: 0;
  display: flex;
  align-items: center;
  gap: 0.75rem;
`;

const Subtitle = styled.p`
  color: #64748b;
  font-size: 0.875rem;
  margin: 0.25rem 0 0 0;
`;

const ChatContainer = styled.div`
  flex: 1;
  overflow-y: auto;
  padding: 1.5rem;
  display: flex;
  flex-direction: column;
`;

const Message = styled.div`
  display: flex;
  gap: 1rem;
  margin-bottom: 1.5rem;
  animation: ${slideIn} 0.3s ease-out;
  
  &.user {
    flex-direction: row-reverse;
    
    .message-content {
      background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
      color: white;
      border-radius: 1rem 0.25rem 1rem 1rem;
    }
  }
  
  &.ai {
    .message-content {
      background: white;
      border: 1px solid #e2e8f0;
      border-radius: 0.25rem 1rem 1rem 1rem;
    }
  }
`;

const Avatar = styled.div`
  width: 2.5rem;
  height: 2.5rem;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  
  &.user {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
  }
  
  &.ai {
    background: #f1f5f9;
    color: #64748b;
  }
`;

const MessageContent = styled.div`
  max-width: 80%;
  padding: 1rem;
  line-height: 1.5;
  
  pre {
    background: #1e293b;
    color: #f8fafc;
    padding: 1rem;
    border-radius: 0.5rem;
    overflow-x: auto;
    margin: 0.5rem 0;
  }
  
  code {
    background: #f1f5f9;
    padding: 0.2rem 0.4rem;
    border-radius: 0.25rem;
    font-family: 'Monaco', 'Consolas', monospace;
  }
`;

const InputContainer = styled.div`
  padding: 1.5rem;
  border-top: 1px solid #e2e8f0;
  background: white;
`;

const InputArea = styled.div`
  display: flex;
  gap: 0.75rem;
  align-items: flex-end;
`;

const Input = styled.textarea`
  flex: 1;
  padding: 0.75rem 1rem;
  border: 1px solid #e2e8f0;
  border-radius: 0.75rem;
  resize: none;
  font-family: inherit;
  font-size: 1rem;
  min-height: 3rem;
  max-height: 12rem;
  
  &:focus {
    outline: none;
    border-color: #667eea;
    box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
  }
`;

const SendButton = styled.button`
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  border: none;
  width: 3rem;
  height: 3rem;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 0.2s ease;
  
  &:hover {
    transform: translateY(-2px);
    box-shadow: 0 4px 12px rgba(102, 126, 234, 0.3);
  }
  
  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    transform: none;
  }
`;

const SuggestionCard = styled.div`
  background: white;
  border: 1px solid #e2e8f0;
  border-radius: 0.75rem;
  padding: 1rem;
  margin-bottom: 1rem;
  cursor: pointer;
  transition: all 0.2s ease;
  
  &:hover {
    border-color: #667eea;
    transform: translateY(-2px);
    box-shadow: 0 4px 12px rgba(102, 126, 234, 0.15);
  }
`;

const SuggestionTitle = styled.h3`
  font-size: 1rem;
  font-weight: 600;
  color: #1e293b;
  margin: 0 0 0.5rem 0;
  display: flex;
  align-items: center;
  gap: 0.5rem;
`;

const SuggestionDescription = styled.p`
  color: #64748b;
  font-size: 0.875rem;
  margin: 0;
  line-height: 1.4;
`;

const LoadingIndicator = styled.div`
  display: flex;
  align-items: center;
  gap: 0.5rem;
  color: #64748b;
  font-size: 0.875rem;
  padding: 1rem;
  
  .dot {
    animation: ${pulse} 1.5s infinite;
    
    &:nth-child(1) { animation-delay: 0s; }
    &:nth-child(2) { animation-delay: 0.5s; }
    &:nth-child(3) { animation-delay: 1s; }
  }
`;

const QuickActions = styled.div`
  display: flex;
  gap: 0.5rem;
  flex-wrap: wrap;
  margin-top: 1rem;
`;

const ActionButton = styled.button`
  background: #f1f5f9;
  border: 1px solid #e2e8f0;
  border-radius: 0.5rem;
  padding: 0.5rem 0.75rem;
  font-size: 0.875rem;
  color: #64748b;
  cursor: pointer;
  transition: all 0.2s ease;
  
  &:hover {
    background: #667eea;
    color: white;
    border-color: #667eea;
  }
`;

function AIChat() {
  const [messages, setMessages] = useState([
    {
      id: 1,
      role: 'assistant',
      content: '👋 Hello! I\'m your AI coding assistant. How can I help you build your application today? You can ask me to generate code, explain concepts, debug issues, or suggest next steps.',
      timestamp: new Date().toISOString()
    }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [suggestions, setSuggestions] = useState([]);
  const chatContainerRef = useRef(null);

  // Auto-resize textarea
  useEffect(() => {
    const textarea = document.querySelector('textarea');
    if (textarea) {
      textarea.style.height = 'auto';
      textarea.style.height = Math.min(textarea.scrollHeight, 192) + 'px';
    }
  }, [inputValue]);

  // Scroll to bottom when messages change
  useEffect(() => {
    if (chatContainerRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!inputValue.trim() || isLoading) return;

    const userMessage = {
      id: Date.now(),
      role: 'user',
      content: inputValue.trim(),
      timestamp: new Date().toISOString()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputValue('');
    setIsLoading(true);

    try {
      const response = await aiChatService.sendMessage(inputValue.trim());
      
      const aiMessage = {
        id: Date.now() + 1,
        role: 'assistant',
        content: response.response,
        timestamp: new Date().toISOString()
      };

      setMessages(prev => [...prev, aiMessage]);
      
      // Get next step suggestions
      const suggestionResponse = await aiChatService.suggestNextSteps({
        lastMessage: inputValue.trim(),
        conversationContext: messages.slice(-3)
      });
      
      setSuggestions(suggestionResponse.suggestions || []);
      
    } catch (error) {
      const errorMessage = {
        id: Date.now() + 1,
        role: 'assistant',
        content: 'Sorry, I encountered an error processing your request. Please try again.',
        timestamp: new Date().toISOString()
      };
      
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSuggestionClick = (suggestion) => {
    setInputValue(suggestion);
  };

  const handleQuickAction = (action) => {
    let prompt = '';
    
    switch (action) {
      case 'generate':
        prompt = 'Generate a React component for a user dashboard with charts and data tables';
        break;
      case 'explain':
        prompt = 'Explain how React hooks work and when to use useState vs useEffect';
        break;
      case 'debug':
        prompt = 'Debug this React component that\'s not updating state properly';
        break;
      case 'optimize':
        prompt = 'Optimize this API endpoint for better performance';
        break;
      case 'stripe':
        prompt = 'Help me integrate Stripe payments into my e-commerce application';
        break;
      case 'google':
        prompt = 'Show me how to integrate Google Drive file storage in my app';
        break;
      case 'deepseek':
        prompt = 'Generate a Python function to process CSV data with pandas';
        break;
      default:
        prompt = action;
    }
    
    setInputValue(prompt);
  };

  return (
    <Container>
      <Sidebar>
        <h2 style={{ fontSize: '1.25rem', fontWeight: '600', color: '#1e293b', marginBottom: '1.5rem' }}>
          <Lightbulb size={20} style={{ verticalAlign: 'middle', marginRight: '0.5rem' }} />
          AI Assistant
        </h2>
        
        <p style={{ color: '#64748b', fontSize: '0.875rem', lineHeight: '1.5', marginBottom: '1.5rem' }}>
          I can help you with code generation, debugging, optimization, and application architecture. 
          Ask me anything about building your application!
        </p>
        
        <h3 style={{ fontSize: '1rem', fontWeight: '600', color: '#1e293b', marginBottom: '1rem' }}>
          Quick Actions
        </h3>
        
        <QuickActions>
          <ActionButton onClick={() => handleQuickAction('generate')}>
            <Code size={16} />
            Generate Code
          </ActionButton>
          <ActionButton onClick={() => handleQuickAction('explain')}>
            <Wrench size={16} />
            Explain Concept
          </ActionButton>
          <ActionButton onClick={() => handleQuickAction('debug')}>
            <Zap size={16} />
            Debug Issue
          </ActionButton>
          <ActionButton onClick={() => handleQuickAction('optimize')}>
            <Sparkles size={16} />
            Optimize Code
          </ActionButton>
          <ActionButton onClick={() => handleQuickAction('stripe')}>
            <span>💳</span>
            Stripe Payments
          </ActionButton>
          <ActionButton onClick={() => handleQuickAction('google')}>
            <span>📊</span>
            Google APIs
          </ActionButton>
          <ActionButton onClick={() => handleQuickAction('deepseek')}>
            <span>🤖</span>
            DeepSeek AI
          </ActionButton>
        </QuickActions>
        
        {suggestions.length > 0 && (
          <div style={{ marginTop: '2rem' }}>
            <h3 style={{ fontSize: '1rem', fontWeight: '600', color: '#1e293b', marginBottom: '1rem' }}>
              Suggested Next Steps
            </h3>
            
            {suggestions.map((suggestion, index) => (
              <SuggestionCard 
                key={index} 
                onClick={() => handleSuggestionClick(suggestion)}
              >
                <SuggestionTitle>
                  <Lightbulb size={16} />
                  {suggestion}
                </SuggestionTitle>
              </SuggestionCard>
            ))}
          </div>
        )}
      </Sidebar>
      
      <MainContent>
        <Header>
          <Title>
            <Bot size={24} />
            AI Coding Assistant
          </Title>
          <Subtitle>Chat with AI to build, debug, and optimize your applications</Subtitle>
        </Header>
        
        <ChatContainer ref={chatContainerRef}>
          {messages.map((message) => (
            <Message key={message.id} className={message.role}>
              <Avatar className={message.role}>
                {message.role === 'user' ? <User size={20} /> : <Bot size={20} />}
              </Avatar>
              <MessageContent className="message-content">
                {message.content}
              </MessageContent>
            </Message>
          ))}
          
          {isLoading && (
            <Message className="ai">
              <Avatar className="ai">
                <Bot size={20} />
              </Avatar>
              <MessageContent className="message-content">
                <LoadingIndicator>
                  <span className="dot">●</span>
                  <span className="dot">●</span>
                  <span className="dot">●</span>
                  <span>AI is thinking...</span>
                </LoadingIndicator>
              </MessageContent>
            </Message>
          )}
        </ChatContainer>
        
        <InputContainer>
          <form onSubmit={handleSubmit}>
            <InputArea>
              <Input
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                placeholder="Ask me anything about building your application..."
                disabled={isLoading}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSubmit(e);
                  }
                }}
              />
              <SendButton 
                type="submit" 
                disabled={!inputValue.trim() || isLoading}
              >
                {isLoading ? <Loader size={20} /> : <Send size={20} />}
              </SendButton>
            </InputArea>
          </form>
        </InputContainer>
      </MainContent>
    </Container>
  );
}

export default AIChat;
